#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_reduce_identity() {
        for x in [0u64, 1, 2013265920, 2013265921, 2013265922, u64::MAX >> 1] {
            assert_eq!(
                BabyBear::reduce(x) % BABYBEAR_P,
                x % BABYBEAR_P,
                "reduce failed"
            );
        }
    }

    #[test]
    fn test_butterfly_roundtrip() {
        let a = 42u64;
        let w = 7u64;
        let b = 99u64;
        let sum = BabyBear::butterfly_sum(a, w, b);
        assert_eq!(sum % BABYBEAR_P, (a + w * b) % BABYBEAR_P);
    }
}
